<template><view class="page"><view class="card"><text class="title">实名认证</text><view class="field"><text>真实姓名</text><input v-model.trim="form.realName" placeholder="请输入真实姓名"/></view><view class="field"><text>身份证号</text><input v-model.trim="form.idCard" placeholder="请输入身份证号"/></view><button class="primary" :loading="loading" @click="submit">提交审核</button></view></view></template><script setup lang="ts">import { ref } from 'vue';import { userApi } from '@/services/user';import { useUserStore } from '@/store/user';const loading=ref(false),form=ref({realName:'',idCard:''});async function submit(){if(!form.value.realName||!form.value.idCard){uni.showToast({title:'请填写实名字段',icon:'none'});return}loading.value=true;try{await userApi.submitRealName(form.value);useUserStore().patchUser({realNameStatus:'PENDING'});uni.showToast({title:'已提交审核',icon:'success'});setTimeout(()=>uni.navigateBack(),400)}finally{loading.value=false}}</script><style scoped lang="scss">.page{min-height:100vh;background:#f6f1e8;color:#24170c}.card{background:#fff;margin:20rpx;padding:28rpx;border-radius:16rpx}.title{font-size:34rpx;font-weight:900}.field{margin-top:24rpx}.field text{display:block;font-weight:700;margin-bottom:12rpx}.field input{height:82rpx;background:#f8f4ed;border-radius:12rpx;padding:0 20rpx}button{margin-top:34rpx;height:86rpx;line-height:86rpx;width:100%;border:0;border-radius:999rpx}.primary{background:#b97700;color:#fff}button:after{border:0}</style>
